import { createClient } from '@supabase/supabase-js'
import type { Database } from './database.types'

// The shared enterprise Supabase project (see u2giants/shared-db). Per-env via
// VITE_SUPABASE_URL / VITE_SUPABASE_ANON_KEY. Preview branch first, then prod.
export const SUPABASE_URL = import.meta.env.VITE_SUPABASE_URL as string | undefined
export const SUPABASE_ANON_KEY = import.meta.env.VITE_SUPABASE_ANON_KEY as string | undefined

if (!SUPABASE_URL || !SUPABASE_ANON_KEY) {
  throw new Error(
    'Missing Supabase configuration: set VITE_SUPABASE_URL and VITE_SUPABASE_ANON_KEY (see .env.example).',
  )
}

// CRM reads go through the `api` views, writes through `crm` tables / `api` RPCs.
// The default PostgREST schema stays `public`; callers pick a schema with
// supabase.schema('api' | 'crm') as needed.
export const supabase = createClient<Database>(SUPABASE_URL, SUPABASE_ANON_KEY, {
  auth: {
    persistSession: true,
    autoRefreshToken: true,
    detectSessionInUrl: true,
  },
})

// Microsoft (Entra) SSO via Supabase Azure provider. Returns into the SPA origin.
export function signInWithMicrosoft(returnTo = window.location.origin + '/') {
  return supabase.auth.signInWithOAuth({
    provider: 'azure',
    options: { scopes: 'email openid profile', redirectTo: returnTo },
  })
}

-- CRM RLS adjustments, realtime, and PostgREST schema exposure for popcrm-web.

-- ---------------------------------------------------------------------------
-- Staff can see each other's profile (internal-tool stance). Needed so the CRM
-- security_invoker views can resolve assignee/owner/salesperson display names,
-- and so assignee/owner pickers work. Baseline only allowed self+admin, which
-- would null out every other user's name in the CRM. Additional permissive
-- SELECT policy: it ORs with the existing profile_select_self_or_admin.
-- ---------------------------------------------------------------------------
drop policy if exists profile_select_staff on app.profile;
create policy profile_select_staff on app.profile
  for select to authenticated
  using (
    app.has_any_role(array['administrator','sales','licensing','designer','viewer','vendor']::app.app_role[])
  );

comment on policy profile_select_staff on app.profile is
  'Internal directory: any authenticated user with a role can read profiles (display name/email/avatar) for assignee/owner pickers.';

-- ---------------------------------------------------------------------------
-- Realtime: add the CRM tables the UI watches that are not already published by
-- the baseline (which already publishes crm.opportunity/task/note/email_message).
-- ---------------------------------------------------------------------------
do $$
declare
  table_name text;
begin
  if exists (select 1 from pg_publication where pubname = 'supabase_realtime') then
    foreach table_name in array array[
      'crm.meeting_note',
      'crm.department',
      'crm.licensor_approval_thread'
    ]
    loop
      if not exists (
        select 1
        from pg_publication_tables
        where pubname = 'supabase_realtime'
          and schemaname = split_part(table_name, '.', 1)
          and tablename = split_part(table_name, '.', 2)
      ) then
        execute format('alter publication supabase_realtime add table %s', table_name);
      end if;
    end loop;
  end if;
end $$;

-- ---------------------------------------------------------------------------
-- Expose the api/crm/pim/core schemas to PostgREST so supabase-js can reach the
-- CRM api views, the crm.* base tables (direct writes), and the api.* RPCs.
-- Supabase only exposes public + graphql_public by default. This is a shared
-- project setting; it is additive (only adds schemas) and RLS still governs all
-- access. PM/PIM also needs api/pim exposed, so this benefits both rewrites.
-- ---------------------------------------------------------------------------
do $$
begin
  execute 'alter role authenticator set pgrst.db_schemas = '
    || quote_literal('public, graphql_public, api, crm, pim, core');
end $$;

notify pgrst, 'reload config';
notify pgrst, 'reload schema';

-- CRM department/company integrity (parity with the Directus
-- enforce-crm-department-scope.sql trigger): a row's department_id, when set,
-- must belong to the row's company_id. When company_id is null but a department
-- is given, the company is backfilled from the department.

create or replace function crm.enforce_department_company()
returns trigger
language plpgsql
as $$
declare
  dept_company uuid;
begin
  if new.department_id is null then
    return new;
  end if;

  select company_id into dept_company
  from crm.department
  where id = new.department_id;

  if dept_company is null then
    raise exception 'crm: department % does not exist', new.department_id
      using errcode = 'foreign_key_violation';
  end if;

  if new.company_id is null then
    new.company_id := dept_company;
  elsif new.company_id <> dept_company then
    raise exception 'crm: department % does not belong to company % (it belongs to %)',
      new.department_id, new.company_id, dept_company
      using errcode = 'check_violation';
  end if;

  return new;
end;
$$;

do $$
declare
  t text;
begin
  foreach t in array array[
    'crm.opportunity',
    'crm.email_message',
    'crm.meeting_note',
    'crm.note',
    'crm.task'
  ]
  loop
    execute format('drop trigger if exists enforce_department_company on %s', t);
    execute format(
      'create trigger enforce_department_company before insert or update on %s
         for each row execute function crm.enforce_department_company()',
      t
    );
  end loop;
end $$;

-- Same rule for a contact's CRM department membership on the relationship row.
create or replace function crm.enforce_contact_company_department()
returns trigger
language plpgsql
as $$
declare
  dept_company uuid;
begin
  if new.crm_department_id is null then
    return new;
  end if;

  select company_id into dept_company
  from crm.department
  where id = new.crm_department_id;

  if dept_company is null then
    raise exception 'crm: department % does not exist', new.crm_department_id
      using errcode = 'foreign_key_violation';
  end if;

  if new.company_id <> dept_company then
    raise exception 'crm: department % does not belong to company %', new.crm_department_id, new.company_id
      using errcode = 'check_violation';
  end if;

  return new;
end;
$$;

drop trigger if exists enforce_contact_company_department on core.contact_company;
create trigger enforce_contact_company_department
  before insert or update on core.contact_company
  for each row execute function crm.enforce_contact_company_department();

