  const { error } = await crmClient.from('department').upsert(depts, { onConflict: 'id' })
  if (error) throw new Error(`crm.department: ${error.message}`)
  console.log(`  ✓ crm.department: ${depts.length} rows`)

  return new Map(rows.map(r => [r.id, r.id]))
}

// ── 3. Buyers → core.contact + core.contact_company ─────────────────────────
async function migrateBuyers(companyMap, deptMap) {
  console.log('\n[3/5] Buyers → core.contact + core.contact_company')
  const rows = await dx('buyer')

  const contacts = rows.map(r => ({
    id: r.id,
    full_name: r.name || [r.first_name, r.last_name].filter(Boolean).join(' ') || null,
    first_name: r.first_name || null,
    last_name: r.last_name || null,
    email: r.email || null,
    phone: r.phone || null,
    title: r.job_title || null,
    metadata: {
      directus_id: r.id,
      external_id: r.external_id || null,
      external_source: r.external_source || null,
      samples_required: r.samples_required ?? null,
    },
  }))

  const coreClient = createClient(SB_URL, SB_KEY, { db: { schema: 'core' } })
  const { error: ce } = await coreClient.from('contact').upsert(contacts, { onConflict: 'id' })
  if (ce) throw new Error(`core.contact: ${ce.message}`)
  console.log(`  ✓ core.contact: ${contacts.length} rows`)

  // contact_company junction rows
  const junctions = rows
    .filter(r => r.retailer)
    .map(r => ({
      contact_id: r.id,
      company_id: companyMap.get(r.retailer) ?? r.retailer,
      relationship_type: 'buyer',
      is_primary: true,
      contact_type: r.contact_type || null,
      scope: r.scope || null,
      crm_department_id: r.department ? (deptMap.get(r.department) ?? null) : null,
    }))

  if (junctions.length) {
    const { error: je } = await coreClient.from('contact_company').upsert(junctions, {
      onConflict: 'contact_id,company_id,relationship_type',
    })
    if (je) throw new Error(`core.contact_company: ${je.message}`)
    console.log(`  ✓ core.contact_company: ${junctions.length} rows`)
  }

  // Back-fill department.primary_contact_id
  const deptPrimaryMap = new Map()
  for (const r of rows) {
    if (r.department && !deptPrimaryMap.has(r.department)) {
      deptPrimaryMap.set(r.department, r.id)
    }
  }
  const dxDepts = await dx('crm_department')
  const deptsWithPrimary = dxDepts
    .filter(d => d.primary_buyer)
    .map(d => ({ id: d.id, primary_contact_id: d.primary_buyer }))
  if (deptsWithPrimary.length) {
    const crmClient = createClient(SB_URL, SB_KEY, { db: { schema: 'crm' } })
    for (const d of deptsWithPrimary) {
      const { error } = await crmClient.from('department').update({ primary_contact_id: d.primary_contact_id }).eq('id', d.id)
      if (error) console.warn(`  ! dept ${d.id} primary_contact update: ${error.message}`)
    }
    console.log(`  ✓ crm.department primary_contact_id: ${deptsWithPrimary.length} updated`)
  }

  return new Map(rows.map(r => [r.id, r.id]))
}

// ── 4. Meeting notes → crm.meeting_note ──────────────────────────────────────
async function migrateMeetings(companyMap, deptMap, contactMap) {
  console.log('\n[4/5] Meeting notes → crm.meeting_note')
  const rows = await dx('crm_meeting_note')

  const meetings = rows.map(r => ({
    id: r.id,
    title: r.name || null,
    meeting_at: r.date || null,
    participants: r.participants || null,
    body: r.summary || null,
    action_items: r.action_items || null,
    source: r.source || null,
    fireflies_transcript_id: r.fireflies_transcript_id || null,
    company_id: r.retailer ? (companyMap.get(r.retailer) ?? r.retailer) : null,
    department_id: r.department ? (deptMap.get(r.department) ?? r.department) : null,
    contact_id: r.contact ? (contactMap.get(r.contact) ?? r.contact) : null,
    metadata: {
      directus_id: r.id,
      external_id: r.external_id || null,
      external_source: r.external_source || null,
    },
  }))

  const crmClient = createClient(SB_URL, SB_KEY, { db: { schema: 'crm' } })
  const { error } = await crmClient.from('meeting_note').upsert(meetings, { onConflict: 'id' })
  if (error) throw new Error(`crm.meeting_note: ${error.message}`)
  console.log(`  ✓ crm.meeting_note: ${meetings.length} rows`)
}

// ── 5. Email messages → crm.email_message ────────────────────────────────────
async function migrateEmails(companyMap, deptMap) {
  console.log('\n[5/5] Email messages → crm.email_message (11k rows, batching)')
  const rows = await dx('crm_email_message')

  const emails = rows.map(r => ({
    id: r.id,
    subject: r.subject || r.name || null,
    sender: r.sender || null,
    recipients: r.recipients || null,
    received_at: r.received_at || null,
    routing_status: r.routing_status || null,
    routing_method: r.routing_method || null,
    body_preview: r.body_preview || null,
    detected_so_numbers: r.detected_so_numbers || null,
    detected_po_numbers: r.detected_po_numbers || null,
    company_id: r.retailer ? (companyMap.get(r.retailer) ?? r.retailer) : null,
    department_id: r.department ? (deptMap.get(r.department) ?? r.department) : null,
    metadata: {
      directus_id: r.id,
      outlook_message_id: r.outlook_message_id || null,
      mailbox_owner: r.mailbox_owner || null,
    },
  }))

  const crmClient = createClient(SB_URL, SB_KEY, { db: { schema: 'crm' } })
  const BATCH = 500
  for (let i = 0; i < emails.length; i += BATCH) {
    const batch = emails.slice(i, i + BATCH)
    const { error } = await crmClient.from('email_message').upsert(batch, { onConflict: 'id' })
    if (error) throw new Error(`crm.email_message batch ${i}: ${error.message}`)
    process.stdout.write(`\r  ✓ crm.email_message: ${Math.min(i + BATCH, emails.length)}/${emails.length}`)
  }
  console.log()
}

// ── main ──────────────────────────────────────────────────────────────────────
try {
  const companyMap = await migrateRetailers()
  const deptMap    = await migrateDepartments(companyMap)
  const contactMap = await migrateBuyers(companyMap, deptMap)
  await migrateMeetings(companyMap, deptMap, contactMap)
  await migrateEmails(companyMap, deptMap)
  console.log('\n✅ Migration complete.')
} catch (e) {
  console.error('\n❌', e.message)
  process.exit(1)
}

