async function dx(collection, params = '') {
  const rows = []
  let offset = 0
  const limit = 500
  while (true) {
    const r = await fetch(`${DX}/items/${collection}?limit=${limit}&offset=${offset}${params}`, {
      headers: { Authorization: `Bearer ${DX_TOKEN}` }
    })
    const j = await r.json()
    if (!j.data?.length) break
    rows.push(...j.data)
    if (j.data.length < limit) break
    offset += limit
  }
  return rows
}

async function upsert(table, rows, schema = 'public') {
  if (!rows.length) return
  const client = schema === 'public' ? sb : createClient(SB_URL, SB_KEY, { db: { schema } })
  const { error } = await client.from(table).upsert(rows, { onConflict: 'id' })
  if (error) throw new Error(`${schema}.${table}: ${error.message}`)
  console.log(`  ✓ ${schema}.${table}: ${rows.length} rows`)
}

