    customer_status: r.customer_status || null,
    chain_type: r.chain_type || null,
    routing_aliases: r.routing_aliases || null,
    so_patterns: r.so_patterns || null,
    metadata: {
      directus_id: r.id,
      logo_url: r.logo_url || null,
      notes: r.notes || null,
      resale_restriction: r.resale_restriction || null,
      external_id: r.external_id || r.id,
      external_source: r.external_source || 'directus',
    },
  }))

  const coreClient = mkClient('core')
