// ── 3. Buyers → core.contact + core.contact_company ─────────────────────────
async function migrateBuyers(companyMap, deptMap) {
  console.log('\n[3/5] Buyers → core.contact + core.contact_company')
  const rows = await dx('buyer')

  const contacts = rows.map(r => ({
    id: r.id,
    full_name: r.name || [r.first_name, r.last_name].filter(Boolean).join(' ') || null,
    first_name: r.first_name || null,
    last_name: r.last_name || null,
    email: r.email || null,
    phone: r.phone || null,
    title: r.job_title || null,
    metadata: {
      directus_id: r.id,
      external_id: r.external_id || r.id,
      external_source: r.external_source || 'directus',
      samples_required: r.samples_required ?? null,
    },
  }))

  const coreClient = mkClient('core')
  const { error: ce } = await coreClient.from('contact').upsert(contacts, { onConflict: 'id' })
  if (ce) throw new Error(`core.contact: ${ce.message}`)
  console.log(`  ✓ core.contact: ${contacts.length} rows`)

  // contact_company junction rows
  const junctions = rows
    .filter(r => r.retailer)
    .map(r => ({
      contact_id: r.id,
      company_id: companyMap.get(r.retailer) ?? r.retailer,
      relationship_type: 'buyer',
      is_primary: true,
      contact_type: r.contact_type || null,
      scope: r.scope || null,
      crm_department_id: r.department ? (deptMap.get(r.department) ?? null) : null,
    }))

  if (junctions.length) {
    const { error: je } = await coreClient.from('contact_company').upsert(junctions, {
      onConflict: 'contact_id,company_id,relationship_type',
    })
    if (je) throw new Error(`core.contact_company: ${je.message}`)
    console.log(`  ✓ core.contact_company: ${junctions.length} rows`)
  }

  // Back-fill department.primary_contact_id
  const deptPrimaryMap = new Map()
  for (const r of rows) {
    if (r.department && !deptPrimaryMap.has(r.department)) {
      deptPrimaryMap.set(r.department, r.id)
    }
  }
  const dxDepts = await dx('crm_department')
  const deptsWithPrimary = dxDepts
    .filter(d => d.primary_buyer)
    .map(d => ({ id: d.id, primary_contact_id: d.primary_buyer }))
  if (deptsWithPrimary.length) {
    const crmClient = mkClient('crm')
    for (const d of deptsWithPrimary) {
      const { error } = await crmClient.from('department').update({ primary_contact_id: d.primary_contact_id }).eq('id', d.id)
      if (error) console.warn(`  ! dept ${d.id} primary_contact update: ${error.message}`)
    }
    console.log(`  ✓ crm.department primary_contact_id: ${deptsWithPrimary.length} updated`)
  }

  return new Map(rows.map(r => [r.id, r.id]))
}

