    process.stdout.write(`\r  ✓ crm.email_message: ${Math.min(i + BATCH, emails.length)}/${emails.length}`)
  }
  console.log()
}

// ── main ──────────────────────────────────────────────────────────────────────
try {
  const companyMap = await migrateRetailers()
  const deptMap    = await migrateDepartments(companyMap)
  const contactMap = await migrateBuyers(companyMap, deptMap)
  await migrateMeetings(companyMap, deptMap, contactMap)
  await migrateEmails(companyMap, deptMap)
  console.log('\n✅ Migration complete.')
} catch (e) {
  console.error('\n❌', e.message)
  process.exit(1)
}

